import React, {useEffect, useState, createContext, useContext, useMemo} from 'react';
import {
  SafeAreaView,
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const AUTH_KEY = 'authenticated';
const PASSWORD_KEY = 'app_password';
const rnBiometrics = new ReactNativeBiometrics();

const AuthContext = createContext(null);

const useAuth = () => useContext(AuthContext);

function AuthProvider({children}) {
  const [loading, setLoading] = useState(true);
  const [authenticated, setAuthenticated] = useState(false);
  const [biometricInfo, setBiometricInfo] = useState({
    available: false,
    biometryType: null,
  });

  useEffect(() => {
    initialize();
  }, []);

  const initialize = async () => {
    try {
      const savedAuth = await AsyncStorage.getItem(AUTH_KEY);
      const {available, biometryType} = await rnBiometrics.isSensorAvailable();

      setBiometricInfo({
        available,
        biometryType: available ? biometryType : null,
      });

      if (savedAuth === 'true') {
        setAuthenticated(true);
      }
    } catch (e) {
      setBiometricInfo({
        available: false,
        biometryType: null,
      });
    } finally {
      setLoading(false);
    }
  };

  const markAuthenticated = async () => {
    await AsyncStorage.setItem(AUTH_KEY, 'true');
    setAuthenticated(true);
  };

  const clearAuthenticated = async () => {
    await AsyncStorage.removeItem(AUTH_KEY);
    setAuthenticated(false);
  };

  const loginWithBiometrics = async () => {
    try {
      const {available, biometryType} = await rnBiometrics.isSensorAvailable();

      if (!available) {
        return {success: false, reason: 'BIOMETRICS_NOT_AVAILABLE'};
      }

      const promptMessage =
        biometryType === ReactNativeBiometrics.FaceID
          ? 'Authenticate with Face ID'
          : biometryType === ReactNativeBiometrics.TouchID
          ? 'Authenticate with Touch ID'
          : 'Authenticate with Biometrics';

      const {success} = await rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Cancel',
      });

      if (success) {
        await markAuthenticated();
        return {success: true};
      }

      return {success: false, reason: 'USER_CANCELLED'};
    } catch (e) {
      return {success: false, reason: 'AUTH_FAILED'};
    }
  };

  const savePassword = async password => {
    await AsyncStorage.setItem(PASSWORD_KEY, password);
  };

  const loginWithPassword = async password => {
    const storedPassword = await AsyncStorage.getItem(PASSWORD_KEY);

    if (!storedPassword) {
      await savePassword(password);
      await markAuthenticated();
      return {success: true, created: true};
    }

    if (storedPassword === password) {
      await markAuthenticated();
      return {success: true, created: false};
    }

    return {success: false};
  };

  const logout = async () => {
    await clearAuthenticated();
  };

  const value = useMemo(
    () => ({
      loading,
      authenticated,
      biometricInfo,
      loginWithBiometrics,
      loginWithPassword,
      logout,
    }),
    [loading, authenticated, biometricInfo],
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

function LoginScreen() {
  const {biometricInfo, loginWithBiometrics, loginWithPassword} = useAuth();
  const [password, setPassword] = useState('');
  const [submitting, setSubmitting] = useState(false);

  const biometricLabel = (() => {
    if (biometricInfo.biometryType === ReactNativeBiometrics.FaceID) {
      return 'Face ID';
    }
    if (biometricInfo.biometryType === ReactNativeBiometrics.TouchID) {
      return 'Touch ID';
    }
    if (biometricInfo.biometryType === ReactNativeBiometrics.Biometrics) {
      return Platform.OS === 'android' ? 'Fingerprint' : 'Biometrics';
    }
    return 'Biometrics';
  })();

  const handleBiometricLogin = async () => {
    setSubmitting(true);
    const result = await loginWithBiometrics();
    setSubmitting(false);

    if (!result.success && result.reason !== 'USER_CANCELLED') {
      Alert.alert('Authentication failed', 'Please try again or use password.');
    }
  };

  const handlePasswordLogin = async () => {
    if (!password.trim()) {
      Alert.alert('Password required', 'Enter your password.');
      return;
    }

    setSubmitting(true);
    const result = await loginWithPassword(password);
    setSubmitting(false);

    if (!result.success) {
      Alert.alert('Invalid password', 'The password you entered is incorrect.');
      return;
    }

    if (result.created) {
      Alert.alert('Password set', 'Your password has been created and you are now logged in.');
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.subtitle}>Authenticate to continue</Text>

        {biometricInfo.available ? (
          <TouchableOpacity
            style={[styles.button, styles.primaryButton]}
            onPress={handleBiometricLogin}
            disabled={submitting}>
            <Text style={styles.primaryButtonText}>
              Continue with {biometricLabel}
            </Text>
          </TouchableOpacity>
        ) : (
          <Text style={styles.helperText}>
            Biometrics are not available on this device. Use your password below.
          </Text>
        )}

        <View style={styles.separator} />

        <TextInput
          value={password}
          onChangeText={setPassword}
          placeholder="Enter password"
          placeholderTextColor="#888"
          secureTextEntry
          style={styles.input}
          editable={!submitting}
        />

        <TouchableOpacity
          style={[styles.button, styles.secondaryButton]}
          onPress={handlePasswordLogin}
          disabled={submitting}>
          <Text style={styles.secondaryButtonText}>
            {biometricInfo.available ? 'Use Password Instead' : 'Login with Password'}
          </Text>
        </TouchableOpacity>

        {submitting && <ActivityIndicator style={styles.loader} />}
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const {logout, biometricInfo} = useAuth();

  const biometricText = biometricInfo.available
    ? biometricInfo.biometryType === ReactNativeBiometrics.FaceID
      ? 'Face ID'
      : biometricInfo.biometryType === ReactNativeBiometrics.TouchID
      ? 'Touch ID'
      : 'Biometrics'
    : 'Password';

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Home</Text>
        <Text style={styles.subtitle}>Authenticated with {biometricText}</Text>
        <TouchableOpacity style={[styles.button, styles.primaryButton]} onPress={logout}>
          <Text style={styles.primaryButtonText}>Logout</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

function RootNavigator() {
  const {loading, authenticated} = useAuth();

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <ActivityIndicator size="large" />
      </SafeAreaView>
    );
  }

  if (authenticated) {
    return <HomeScreen />;
  }

  return <LoginScreen />;
}

export default function App() {
  return (
    <AuthProvider>
      <RootNavigator />
    </AuthProvider>
  );
}

